local TD = TD.td1madao["ydj_dst_td1madao"] TD.createFn("exeClient", function(name, param, player)     if not param then param = {} end     if not param.inst then param.inst = player or TD.GetPlayer() end     local client = TD.G.CLIENT_FN     if not client or not name or not client[name] then         return     end     client[name](param or {}) end) TD.createFn("exeServer", function(name, param, player)     if not param then param = {} end     if not param.inst then param.inst = player or TD.GetPlayer() end     local server = TD.G.SERVER_FN     if not server or not name or not server[name] then         return     end     server[name](param or {}) end) TD.createFn("clientFn", function(name, fn)     if not name or not fn then         return     end     TD.default(TD.default(TD.G, TD.CONST.CLIENT_FN_STR), name, fn) end) TD.createFn("serverFn", function(name, fn)     if not name or not fn then         return     end     TD.default(TD.default(TD.G, TD.CONST.SERVER_FN_STR), name, fn) end) TD.createFn("serverCall", function(name, param, target)     if TD.ds() then     end     local server = TD.G.SERVER_FN     if not server or not name then         return     end     if not param then         param = {}     end     local targetObj = param.target     param.target = nil     TD.server(function()         local inst = TD.GetPlayer()         param.inst = inst         param.target = targetObj or target         if TD.G.SERVER_FN[name] then             TD.G.SERVER_FN[name](param)         end     end, function()         if param.player then             param.player = nil         end         if param.inst then             param.inst = nil         end         TD.try(function()             local res = TD.encode(param)             TD.debug(res, true)             SendModRPCToServer(MOD_RPC[TD.ACTIONSPACE][TD.ACTION], name, res, targetObj or target)         end)     end) end) TD.createFn("callFn", function(inst, fnName, arg)     local param = {}     param.fnName = fnName     param.arg = arg or {}     TD.mgn(inst, function(comp)         comp:server_send(TD.holder("%s_call_self"), param)     end) end) 